import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://api.example.com/dev"
        case .staging:
            return "https://api.example.com/stage"
        case .production:
            return "https://api.example.com/prod"
        }
    }
}

struct NetworkManager {
    
    static let shared = NetworkManager()
    private init() {}
    
    func fetchUserData(completion: @escaping (Result<UserData, Error>) -> Void) {
        guard let url = URL(string: "\(Environment.shared.baseURL)/user") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data returned", code: -1)))
                return
            }
            
            do {
                let userData = try JSONDecoder().decode(UserData.self, from: data)
                completion(.success(userData))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
    
    func authenticate(with username: String, password: String, completion: @escaping (Result<AuthResponse, Error>) -> Void) {
        guard let url = URL(string: "\(Environment.shared.baseURL)/auth") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: parameters)
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data returned", code: -1)))
                return
            }
            
            do {
                let authResponse = try JSONDecoder().decode(AuthResponse.self, from: data)
                completion(.success(authResponse))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
}

struct UserData: Codable {
